// nodes/outputNode.js
import { useState } from 'react';
import { BaseNode, fieldStyle } from './BaseNode';
import { useStore } from '../store';

export const OutputNode = ({ id, data }) => {
  const updateNodeField = useStore((s) => s.updateNodeField);
  const [name, setName] = useState(data?.outputName ?? id.replace('customOutput-', 'output_'));
  const [type, setType] = useState(data?.outputType ?? 'Text');

  return (
    <BaseNode
      id={id}
      title="Output"
      icon="⬆"
      accentColor="#34d399"
      inputs={[{ id: 'value', label: 'value' }]}
    >
      <div style={fieldStyle.group}>
        <label style={fieldStyle.label}>Name</label>
        <input
          style={fieldStyle.input}
          value={name}
          onChange={(e) => {
            setName(e.target.value);
            updateNodeField(id, 'outputName', e.target.value);
          }}
        />
      </div>
      <div style={fieldStyle.group}>
        <label style={fieldStyle.label}>Type</label>
        <select
          style={fieldStyle.select}
          value={type}
          onChange={(e) => {
            setType(e.target.value);
            updateNodeField(id, 'outputType', e.target.value);
          }}
        >
          <option>Text</option>
          <option>Image</option>
          <option>File</option>
        </select>
      </div>
    </BaseNode>
  );
};
